public int compress(char[] chars) {
    int index = 0, count;
    for(int i = 0; i < chars.length; i += count) {
        count = 1;
        while(i + count < chars.length && chars[i] == chars[i + count]) {
            count++;
        }
        chars[index++] = chars[i];
        if(count > 1) {
            for(char c : Integer.toString(count).toCharArray()) {
                chars[index++] = c;
            }
        }
    }
    return index;
}
```

